    for (mask in 1 until (1 shl n)) {
        val subsetNodes = mutableListOf<Int>()
        var sum = 0L
        for (i in 0 until n) {
            if ((mask and (1 shl i)) != 0) {
                subsetNodes.add(i)
                sum += nums[i]
            }
        }

        // Condition 2: Check if the sum of values is even
