 * Checks if the induced subgraph defined by the bitmask 'mask' is connected.
 * Uses Breadth-First Search (BFS) restricted to nodes in the mask.
 */
fun isInducedSubgraphConnected(mask: Int, n: Int, adj: Array<MutableList<Int>>): Boolean {
    val nodesInSubset = mutableListOf<Int>()
    for (i in 0 until n) {
        if ((mask and (1 shl i)) != 0) {
            nodesInSubset.add(i)
        }
    }

    if (nodesInSubset.isEmpty()) return false // Should not happen given the loop structure

    val startNode = nodesInSubset[0]
    val visited = BooleanArray(n) { false }
    val queue: Queue<Int> = LinkedList()

    queue.add(startNode)
    visited[startNode] = true
    var visitedCount = 0

    while (queue.isNotEmpty()) {
        val u = queue.poll()
        visitedCount++

        // Iterate over neighbors of u in the original graph
        for (v in adj[u]) {
            // Check if v is in the subset (mask) AND has not been visited
            if ((mask and (1 shl v)) != 0 && !visited[v]) {
                visited[v] = true
                queue.add(v)
            }
        }
    }

    // The subgraph is connected if and only if BFS starting from any node 
    // in the subset reaches all other nodes in the subset.
    return visitedCount == nodesInSubset.size
